6:function request(method, path, body, token) {
7:  return new Promise((resolve, reject) => {
8:    const payload = body ? JSON.stringify(body) : null;
9:    const headers = { 'content-type': 'application/json' };
10:    if (token) headers.authorization = `Bearer ${token}`;
11:    const req = http.request({ hostname: parsedBase.hostname, port: Number(parsedBase.port || 80), path, method, headers }, (res) => {
12:      let data = '';
13:      res.on('data', (c) => (data += c));
14:      res.on('end', () => resolve({ status: res.statusCode, body: data ? JSON.parse(data) : {} }));
15:    });
16:    req.on('error', reject);
17:    if (payload) req.write(payload);
18:    req.end();
19:  });
20:}
