1:(function(){
2:	const pino = require('pino');
3:	const { env } = require('../config');
4:
5:	const pinoLogger = pino({ level: env.LOG_LEVEL || 'debug', base: null, timestamp: pino.stdTimeFunctions.isoTime });
6:
7:	function fmtTags(tags) {
8:		if (!tags) return '';
9:		if (Array.isArray(tags)) return tags.map(t => `[${String(t)}]`).join('');
10:		return `[${String(tags)}]`;
11:	}
12:
13:	function formatMessage(tags, msg) { return `${fmtTags(tags)} ${msg}`; }
14:
15:	const SENSITIVE_KEYS = ['password','password_hash','ssn','ssn_encrypted','authorization','auth','token','session','cookie','credit_card','cc','cvv','secret','apiKey','apikey','reauthPassword'];
16:
17:	function sanitizeValue(val) {
18:		if (val === null || val === undefined) return val;
19:		if (typeof val === 'string') return val;
20:		if (typeof val === 'number' || typeof val === 'boolean') return val;
21:		if (Array.isArray(val)) return val.map(sanitizeValue);
22:		if (typeof val === 'object') return sanitizeObject(val);
23:		return val;
24:	}
25:
26:	function sanitizeObject(obj) {
27:		if (!obj || typeof obj !== 'object') return obj;
28:		const out = Array.isArray(obj) ? [] : {};
29:		for (const k of Object.keys(obj)) {
30:			try {
31:				if (SENSITIVE_KEYS.includes(k)) {
32:					out[k] = '***REDACTED***';
33:				} else {
34:					out[k] = sanitizeValue(obj[k]);
35:				}
36:			} catch (e) {
37:				out[k] = '***REDACTED***';
38:			}
39:		}
40:		return out;
41:	}
42:
43:	function sanitize(input) {
44:		try {
45:			if (input == null) return input;
46:			if (typeof input === 'object') return sanitizeObject(input);
47:			return input;
48:		} catch (e) { return '***REDACTED***'; }
49:	}
50:
51:	const api = {
52:		pino: pinoLogger,
53:		info: (tags, msg, meta) => pinoLogger.info({ meta: sanitize(meta) }, formatMessage(tags, msg)),
54:		warn: (tags, msg, meta) => pinoLogger.warn({ meta: sanitize(meta) }, formatMessage(tags, msg)),
55:		error: (tags, msg, meta) => pinoLogger.error({ meta: sanitize(meta) }, formatMessage(tags, msg)),
56:		debug: (tags, msg, meta) => pinoLogger.debug({ meta: sanitize(meta) }, formatMessage(tags, msg)),
57:		child: (obj) => pinoLogger.child(obj),
58:		sanitize
59:	};
60:
61:	// fastify plugin to attach hooks
62:	async function plugin(fastify, opts) {
63:		 // attach logger helpers to fastify
64:		 try { fastify.decorate('logger', api); } catch (e) { fastify.logger = api; }
65:		 // ensure `fastify.log` is bound to our pino instance for consistency
66:		 try { fastify.decorate('log', pinoLogger); } catch (e) { fastify.log = pinoLogger; }
67:
68:		fastify.addHook('onRequest', async (request, reply) => {
69:			try {
70:				request._startTime = Date.now();
71:				const ip = request.ip || request.socket && request.socket.remoteAddress;
72:				// generate correlation id for this request
73:				const { v4: uuidv4 } = require('uuid');
74:				const cid = uuidv4();
75:				request.requestId = cid;
76:				// attach a child logger with cid so entries include it
77:				try { request.log = pinoLogger.child({ cid }); } catch (e) { request.log = pinoLogger; }
78:				if (reply && typeof reply.header === 'function') reply.header('X-Request-Id', cid);
79:				api.info(['req','incoming', request.method, request.raw.url, `cid:${cid}`], `from ${ip}`, { ip, cid });
80:				// Also print a concise console line so requests are visible in environments
81:				try { console.log(`[req] ${request.method} ${request.raw.url} cid=${cid} ip=${ip}`); } catch (e) { /* swallow */ }
82:			} catch (e) { /* swallow */ }
83:		});
84:
85:		fastify.addHook('onResponse', async (request, reply) => {
86:			try {
87:				const dur = Date.now() - (request._startTime || Date.now());
88:				const cid = request.requestId || null;
89:				api.info(['req','completed', request.method, request.raw.url, `status:${reply.statusCode}`, `cid:${cid}`], `completed in ${dur}ms`, { cid, durationMs: dur });
90:				try { console.log(`[res] ${request.method} ${request.raw.url} status=${reply.statusCode} cid=${cid} dur=${dur}ms`); } catch (e) { /* swallow */ }
91:			} catch (e) { /* swallow */ }
92:		});
93:	}
94:
95:	module.exports = { pino: pinoLogger, plugin, info: api.info, warn: api.warn, error: api.error, debug: api.debug, child: api.child, sanitize: api.sanitize };
96:})();
